"""One-off: align the 38 non-escalation ground-truth answers in golden_test_set.csv
with the runbook content at the system's answer granularity (same approach as the
escalation GT alignment). Every clause is verifiable from the runbook sections the
case cites. Safe to delete after use."""

import csv

CSV_PATH = "eval/golden_test_set.csv"

